it('should complete faster with approximation', async () => {
  // Create larger graph
  const entities = Array.from({ length: 200 }, (_, i) => ({
    name: `Entity${i}`,
    entityType: 'test',
    observations: [],
  }));
  await storage.saveGraph({ entities, relations: [] });

  const startFull = Date.now();
  await graphTraversal.calculateBetweennessCentrality({ approximate: false });
  const fullTime = Date.now() - startFull;

  const startApprox = Date.now();
  await graphTraversal.calculateBetweennessCentrality({ approximate: true, sampleRate: 0.2 });
  const approxTime = Date.now() - startApprox;

  expect(approxTime).toBeLessThan(fullTime);
});
